import logo from './logo.svg';
import './App.css';
import { useState } from 'react';
import { Block,Block_with_input } from './Block';

function App() {
    const [color_input, setColor_input] = useState({
        red: 0,
        green: 0,
        blue: 0,
    });
    const handleChange = (input) => e => {
        setColor_input({ ...color_input, [input]: e.target.value });
    };
    const col = {
        red: 200,
        blue: 0,
        green: 0,
    }
    const [is_visible, setIs_visible] = useState(true);
    return (
        <div className="App">
            <header className="App-header">
                <Block color_rgb={col} text="問題"></Block>
                <Block_with_input is_visible={true} text="正解"></Block_with_input>
            </header>
        </div>
    );
}

export default App;
